qry:select.qry:xquery:
	for $r in sql('
	SELECT 
		TAR.oi_tarea,
		TAR.d_tarea,
		TAR.f_tarea,
		TAR.f_vto_tarea,
		TAR.d_lugar_tarea,
		TAR.o_tarea,
		SUJ.c_sujeto,
		SUJ.d_sujeto,
		CAR.oi_carpeta,
		CAR.c_carpeta,
		CAR.d_carpeta,
		EST.d_estado_tarea,
		TIP.d_tipo_tarea,
		EMP.c_empresa,
		EMP.d_empresa,
		EMP.oi_empresa,
		CAR.oi_ubicacion

	FROM
		LEG03_TAREAS as TAR,
		LEG40_CLASIF_SUJ as CLA,
		LEG40_SUJETOS as SUJ,
		LEG01_CARPETAS as CAR,
		LEG34_ESTADOS_TAREAS as EST,
		LEG35_TIPOS_TAREAS as TIP,
		ORG03_EMPRESAS as EMP

	JOIN
		EMP.oi_empresa INNER CAR.oi_empresa,
		TAR.oi_carpeta INNER CAR.oi_carpeta,
		TAR.oi_clasif_sujeto INNER CLA.oi_clasif_sujeto,
		CLA.oi_sujeto INNER SUJ.oi_sujeto,
		TAR.oi_estado_tarea INNER EST.oi_estado_tarea,
		TAR.oi_tipo_tarea INNER TIP.oi_tipo_tarea

	WHERE
	CAR.oi_estado_carpeta != 11 AND
	CAR.oi_carpeta IN ({%=$PARAM/@oi_carpeta%})

		{%? (#FILTRO:@oi_empresa!='')                  
			{% AND EMP.oi_empresa = {#FILTRO:@oi_empresa} %} 
			{% %} 
		%}

		{%? (#FILTRO:@oi_carpeta!='')                  
			{% AND TAR.oi_carpeta = {#FILTRO:@oi_carpeta} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_clasif_sujeto!='')                  
			{% AND TAR.oi_clasif_sujeto = {#FILTRO:@oi_clasif_sujeto} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_estado_tarea!='')                  
			{% AND TAR.oi_estado_tarea = {#FILTRO:@oi_estado_tarea} %} 
			{% %} 
		%}
		{%? (#FILTRO:@oi_tipo_tarea!='')                  
			{% AND TAR.oi_tipo_tarea = {#FILTRO:@oi_tipo_tarea} %} 
			{% %} 
		%}
		{%? (#FILTRO:@d_tarea!='')                  
			{% AND CONTAIN(TAR.d_tarea, \'{%=#FILTRO:@d_tarea%}\') %} 
			{% %} 
		%}
		{%? (#FILTRO:@d_lugar_tarea!='')                  
			{% AND CONTAIN(TAR.d_lugar_tarea, \'{%=#FILTRO:@d_lugar_tarea%}\') %} 
			{% %} 
		%}
		{%?(#FILTRO:@f_tarea_d!='') 
			{% AND TAR.f_tarea >= {#FILTRO:@f_tarea_d} %} 
			{% %} 
		%}
		{%?(#FILTRO:@f_tarea_h!='') 
			{% AND TAR.f_tarea <  {Datetime(Number(Datetime(#FILTRO:@f_tarea_h))+1)} %} 
			{% %} 
		%}
		{%?(#FILTRO:@f_vto_tarea_d!='') 
			{% AND TAR.f_vto_tarea >= {#FILTRO:@f_vto_tarea_d} %} 
			{% %} 
		%}
		{%?(#FILTRO:@f_vto_tarea_h!='') 
			{% AND TAR.f_vto_tarea <  {Datetime(Number(Datetime(#FILTRO:@f_vto_tarea_h))+1)} %} 
			{% %} 
		%}										
	ORDER BY c_empresa ASC
')/ROWS/ROW
